import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"空洞骑士护符组","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/空洞骑士护符组.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/空洞骑士护符组.md"}'),s={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/空洞骑士护符组.md"};function o(d,b,_,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"空洞骑士护符组",tabindex:"-1"},[t("空洞骑士护符组 "),r("a",{class:"header-anchor",href:"#空洞骑士护符组","aria-label":'Permalink to "空洞骑士护符组"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),n('<h1 id="空洞骑士护符组-1" tabindex="-1">空洞骑士护符组 <a class="header-anchor" href="#空洞骑士护符组-1" aria-label="Permalink to &quot;空洞骑士护符组&quot;">​</a></h1><p>空洞骑士护符组</p><p>该护符组下属奇物共同占据一个护符位。<br> 尽管如此，多个护符将具有一个装备上限，每个护符都会占据一定数量的护符槽，你一开始会有3个护符槽，当你佩戴下列任意护符每通过一场影片，就可以花费累计250分的货币额外开启一个护符槽，至多开启至7个护符槽。</p><p>任性的指南针<br> 250<br> 占据护符槽：1<br> 当你持有这个护符时，你走过的地区的地图将会出现在你的轮回者手表上（借助了某种媒介传递），这是一个无支线的信息共享效果。<br> ——————————————</p><p>采集虫群<br> 250<br> 占据护符槽：1<br> 虫群将跟随持有者并收集任何散落的吉欧。<br> 适合那些无论多细小的东西都不愿意丢下的人。<br> 在每次同级战斗之后，虫群会把对方身上的有价值之物带给你，这意味着你会获得价值15分的当地货币，每影片至多触发这一特性10次。<br> ————————————————————</p><p>坚硬外壳<br> 500<br> 占据护符槽：2<br> 加强韧性。当从伤害中恢复时，延长持有者保持不受伤害的时间。<br> 使其更容易在危险情形下逃脱。<br> 当你使用招架获得伤害抵消的时候，在本轮中获得2格挡防御。<br> ——————————————</p><p>灵魂捕手<br> 500<br> 占据护符槽：2<br> 萨满曾用它来从周围的世界中吸取更多灵魂。<br> 增加用骨钉攻击敌人时获得的灵魂数量。<br> 获得时绑定一个能量池，使那个能量池的上限增加6点，但是由该护符增加的能量池现在开始无法正常使用，这之后每当你使用近战攻击击中时，使其中等同于造成伤害*1点能量池解锁。<br> ————————————————</p><p>萨满之石<br> D+500<br> 占据护符槽：3<br> 据说包含前代萨满的学识。<br> 提高法术的威力，对敌人造成更多伤害。<br> 该护符会提供4点法术强度，同时你的施法攻击额外具有【破魔5】<br> ————————————————————</p><p>噬魂者<br> D+500<br> 占据护符槽：4<br> 被遗忘的萨满神器，用来从活着的生物身上吸取灵魂。<br> 大大增加用骨钉攻击敌人时获得的灵魂数量。<br> 获得时绑定一个能量池，使那个能量池的上限增加9点，但是由该护符增加的能量池现在开始无法正常使用，这之后每当你使用近战攻击击中时，使其中等同于造成伤害*1点能量池解锁。<br> 每携带该护符经历一次同级战斗并且获胜，该护符提供的能量池上限增加1点，每影片至多触发这一特性6次。<br> ——————————————</p><p>冲刺大师<br> D+500<br> 占据护符槽：2<br> 有着被称为“冲刺大师”的古怪虫子形象。<br> 持有者将能够更频繁地冲锋，也能向下冲锋（这应该是画风）。非常适合那些想要快速移动的虫子。<br> 现在当你使用冲锋时，你的冲锋距离取最大计算，并且在你冲锋开始之前，你可以以一个自由动作朝任意方向移动15M。<br> ————————</p><p>飞毛腿<br> 500<br> 占据护符槽：1<br> 有着被称为“飞毛腿”的古怪虫子形象。<br> 增加持有者的奔跑速度，使其能避开危险或追上敌人。<br> 你的基础移速增加10M。<br> ————————</p><p>坚固贪婪<br> 500<br> 占据护符位：2<br> 使得持有者在击败敌人时能找到更多的吉欧。<br> 这个护符很坚固，不会破碎。<br> 当你击杀同级敌人时，你可以从敌人的尸体上找到25分价值的等价物，也可能被替换为25分等价的材料，每影片至多触发这一特性10次。</p><p>坚固力量<br> 250<br> 占据护符位：2<br> 增强持有者的攻击力，使其骨钉能够对敌人造成更多伤害。<br> 这个护符很坚固，不会破碎。<br> 持有者的近战攻击检定额外获得1DP的器械加值。</p><p>法术扭曲者<br> 250<br> 占据护符位：2<br> 反映了灵魂圣所掌握灵魂力量的欲望，可以提高持有者的施法能力。<br> 减少法术的灵魂消耗。<br> 获得时绑定一个能量池，当你消耗那个能量时，一轮一次，你可以减少其1点消耗（最低到1）。<br> ————————</p><p>沉重之击<br> 1500<br> 占据护符位：2<br> 阵亡战士的骨钉形成。<br> 增加持有者骨钉的力量，使敌人在被击中时后退的距离更远。<br> 一轮一次，当你的近战攻击命中时，你可以对敌人进行一次冲撞，对方在这次冲撞中，额外被击退10M。</p><p>快速劈砍<br> 1500<br> 占据护符位：3<br> 诞生于那些被融合的不完美的废弃骨钉。<br> 允许持有者更快地挥砍骨钉。<br> 你的近战攻击额外具有【连射】效果。</p><p>修长之钉<br> 250<br> 占据护符位：2<br> 增加持有者骨钉的攻击范围，允许打击更远处的敌人。<br> 你的触及距离增加1M。<br> ——————</p><p>骄傲印记<br> 750<br> 占据护符位：3<br> 由螳螂部落慷慨赠予他们尊敬的人。<br> 大大增加持有者骨钉的攻击范围，使其能够从更远处劈砍敌人。<br> 你的触及距离增加3M。</p><p>亡者之怒<br> 1000<br> 占据护符位：2<br> 体现了那些将死之人的愤怒和英勇。<br> 当接近死亡时，持有者的力量会增加。<br> 当你的生命槽中一半严重伤害填充时，你的攻击检定额外获得2DP内在加值。<br> 当你没有完好时，额外获得3DP内在加值。</p><p>苦痛荆棘<br> D+500<br> 占据护符位：1<br> 感受持有者的痛苦并鞭打周围的世界。<br> 当受到伤害时，产生荆棘藤蔓伤害附近的敌人。<br> 当你被攻击命中时，对攻击来源造成1点穿刺严重伤害。<br> ———————</p><p>巴德尔之壳<br> D+500<br> 占据护符位：2<br> 在凝聚灵魂时，产生硬壳保护它的持有者。<br> 外壳不是无法破坏的，吸收太多的伤害后将会破碎。<br> 当你具有快速医疗，并且该快速医疗生效时开始生效，该护符位会持有者提供【活体护甲】2点和1点盔甲防御<br> ————————</p><p>发光子宫<br> D+500<br> 占据护符槽：2<br> 从持有者的身上汲取灵魂，用来产生幼崽。<br> 幼崽没有进食或成长的意愿，并会牺牲自己来保护它们的父母。<br> 在处于战斗状态下，你每轮结束时都会生成一只小飞虫（你也可以选择生成缩小版或是幼化的自己），每生成一只，你都需要支付1点能量，当你攻击时，你可以指挥任意数量的小飞虫对敌人发动自爆袭击，这会使你的攻击在命中后增加消耗小飞虫数量*1点的能量严重伤害。<br> ————————</p><p>快速凝聚<br> D+500<br> 占据护符槽：3<br> 包含水晶镜片的护符。<br> 提升灵魂的凝聚速度，让持有者更快地治愈伤口。<br> 你获得快速医疗2（32医疗点）。<br> ————————</p><p>深度凝聚<br> D+500<br> 占据护符槽：4<br> 在水晶内长时间自然形成。从周围的空气中吸取灵魂。<br> 持有者会以更慢的速度凝聚灵魂，但治疗效果会加倍。<br> 你获得快速医疗1（52医疗点），当你使用这个快速医疗效果回复伤势时，可以消耗一个标准动作使回复的伤势增加2点<br> ——————————</p><p>生命血之心<br> 500<br> 占据护符槽：2<br> 包含一个活着的核心，浸出宝贵的生命血。<br> 休息时，持有者被生命血包裹，可以防止少量伤害。<br> 持有者获得1点临时生命，每场景开始时恢复。<br> ————————</p><p>生命血核心<br> D+500<br> 占据护符槽：3<br> 包含一个活着的核心，流出宝贵的生命血。<br> 休息时，持有者被生命血包裹，可以防止大量伤害。<br> 持有者获得3点临时生命，每场景恢复，当临时生命没有被全部击破时，获得1点天生防御。</p><p>蜂巢之血<br> D+1000<br> 占据护符槽：4<br> 蜂巢中珍贵的金色硬化花蜜块。<br> 随时间修复持有者的伤口，使其回复生命值而不需凝聚灵魂。<br> 获得2点临时生命，由这个护符带来的临时生命会每轮刷新，当临时生命没有被全部击破时，获得1点天生防御。<br> ————————</p><p>锋利之影<br> D+500<br> 占据护符位：2<br> 含有被禁用的法术，能将影子转换为致命的武器。<br> 当使用暗影冲刺时，持有者的身体会变得锋利，并伤害敌人。<br> 以一个整轮动作启用，你化身为一道暗影冲刺而过，这是一个类冲锋招式，并且你可以同时攻击冲锋路径上的全部敌人，这次冲锋攻击中，即使敌人离开了你的攻击范围，你也可以按照脱离攻击范围一样攻击。<br> ————————</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',30)])])}const f=p(s,[["render",o]]);export{D as __pageData,f as default};
